static int jayess_raylib_windowed_height = 0;
static int jayess_raylib_window_fullscreen = 0;

#define JAYESS_RAYLIB_LOGICAL_FULLSCREEN_WIDTH 1920
#define JAYESS_RAYLIB_LOGICAL_FULLSCREEN_HEIGHT 1080

static unsigned char jayess_raylib_color_channel(jayess_object *object, const char *key, const char *context) {
    jayess_value *value = jayess_object_get(object, key);
    double number;
    if (value == NULL) {
        jayess_throw_type_error(context);
        return 0;
    }
    number = jayess_value_to_number(value);
    if (number < 0) number = 0;
    if (number > 255) number = 255;
    return (unsigned char) number;
}

static Color jayess_raylib_expect_color(jayess_value *value, const char *context) {
    jayess_object *object = jayess_expect_object(value, context);
    Color color = { 0, 0, 0, 255 };
    if (jayess_has_exception()) {
        return color;
    }
    color.r = jayess_raylib_color_channel(object, "r", context);
    if (jayess_has_exception()) return color;
    color.g = jayess_raylib_color_channel(object, "g", context);
    if (jayess_has_exception()) return color;
    color.b = jayess_raylib_color_channel(object, "b", context);
    if (jayess_has_exception()) return color;
    color.a = jayess_raylib_color_channel(object, "a", context);
    return color;
}

static jayess_value *jayess_raylib_value_from_vector2(Vector2 value) {
    jayess_object *object = jayess_object_new();
    jayess_object_set_value(object, "x", jayess_value_from_number((double) value.x));
    jayess_object_set_value(object, "y", jayess_value_from_number((double) value.y));
    return jayess_value_from_object(object);
}

static int jayess_raylib_string_equals_ignore_case(const char *left, const char *right) {
    if (left == NULL || right == NULL) {
        return 0;
    }
    while (*left != '\0' && *right != '\0') {
        if (tolower((unsigned char)*left) != tolower((unsigned char)*right)) {
            return 0;
        }
        left++;
        right++;
    }
    return *left == '\0' && *right == '\0';
}

static int jayess_raylib_is_ppm_extension(const char *file_type) {
    return jayess_raylib_string_equals_ignore_case(file_type, ".ppm") ||
           jayess_raylib_string_equals_ignore_case(file_type, "ppm");
}

static void jayess_raylib_skip_ppm_space_and_comments(const unsigned char *data, size_t length, size_t *index) {
    while (*index < length) {
        if (isspace(data[*index])) {
            (*index)++;
            continue;
        }
        if (data[*index] == '#') {
            while (*index < length && data[*index] != '\n') {
                (*index)++;
            }
            continue;
        }
        break;
    }
}

static int jayess_raylib_read_ppm_number(const unsigned char *data, size_t length, size_t *index, int *value) {
    int number = 0;
    int found_digit = 0;
    jayess_raylib_skip_ppm_space_and_comments(data, length, index);
    while (*index < length && isdigit(data[*index])) {
        found_digit = 1;
        number = (number * 10) + (data[*index] - '0');
        (*index)++;
    }
    if (!found_digit) {
        return 0;
    }
    *value = number;
    return 1;
}

static Image jayess_raylib_load_ppm_from_memory(const unsigned char *data, size_t length) {
    Image image = { 0 };
    int width = 0;
    int height = 0;
    int max_value = 0;
    size_t index = 0;
    size_t pixel_count;
    Color *pixels;
    size_t i;
    if (data == NULL || length < 11) {
        return image;
    }
    if (data[0] != 'P' || data[1] != '6') {
        return image;
    }
    index = 2;
    if (!jayess_raylib_read_ppm_number(data, length, &index, &width) ||
        !jayess_raylib_read_ppm_number(data, length, &index, &height) ||
        !jayess_raylib_read_ppm_number(data, length, &index, &max_value)) {
        return image;
    }
    if (width <= 0 || height <= 0 || max_value != 255) {
        return image;
    }
    if (index >= length || !isspace(data[index])) {
        return image;
    }
    while (index < length && isspace(data[index])) {
        index++;
    }
    pixel_count = (size_t) width * (size_t) height;
    if (pixel_count == 0 || length - index < pixel_count * 3) {
        return image;
    }
    pixels = (Color *) RL_MALLOC(pixel_count * sizeof(Color));
    if (pixels == NULL) {
        return image;
    }
    for (i = 0; i < pixel_count; i++) {
        size_t base = index + (i * 3);
        pixels[i].r = data[base + 0];
        pixels[i].g = data[base + 1];
        pixels[i].b = data[base + 2];
        pixels[i].a = 255;
    }
    image.data = pixels;
    image.width = width;
    image.height = height;
    image.mipmaps = 1;
    image.format = PIXELFORMAT_UNCOMPRESSED_R8G8B8A8;
    return image;
}

static Image jayess_raylib_load_ppm_from_file(const char *path) {
    Image image = { 0 };
    FILE *file = fopen(path, "rb");
    unsigned char *buffer = NULL;
    long file_size;
    size_t read_count;
    if (file == NULL) {
        return image;
    }
    if (fseek(file, 0, SEEK_END) != 0) {
        fclose(file);
        return image;
    }
    file_size = ftell(file);
    if (file_size <= 0 || fseek(file, 0, SEEK_SET) != 0) {
        fclose(file);
        return image;
    }
    buffer = (unsigned char *) malloc((size_t) file_size);
    if (buffer == NULL) {
        fclose(file);
        return image;
    }
    read_count = fread(buffer, 1, (size_t) file_size, file);
    fclose(file);
    if (read_count != (size_t) file_size) {
        free(buffer);
        return image;
    }
    image = jayess_raylib_load_ppm_from_memory(buffer, read_count);
    free(buffer);
    return image;
}

static void jayess_raylib_image_finalize(void *handle) {
    Image *image = (Image *) handle;
    if (image != NULL) {
        if (IsImageValid(*image)) {
            UnloadImage(*image);
        }
        free(image);
    }
}

static void jayess_raylib_texture_finalize(void *handle) {
    Texture2D *texture = (Texture2D *) handle;
    if (texture != NULL) {
        if (IsTextureValid(*texture)) {
            UnloadTexture(*texture);
        }
        free(texture);
    }
}

static jayess_value *jayess_raylib_wrap_image(Image image, const char *message) {
    Image *stored = NULL;
    if (!IsImageValid(image)) {
        jayess_throw_named_error("RaylibError", message);
        return jayess_value_undefined();
    }
    stored = (Image *) malloc(sizeof(Image));
    if (stored == NULL) {
        UnloadImage(image);
        jayess_throw_error("failed to allocate raylib image handle");
        return jayess_value_undefined();
    }
    *stored = image;
    return jayess_value_from_managed_native_handle("RaylibImage", stored, jayess_raylib_image_finalize);
}

static jayess_value *jayess_raylib_wrap_texture(Texture2D texture, const char *message) {
    Texture2D *stored = NULL;
    if (!IsTextureValid(texture)) {
        jayess_throw_named_error("RaylibError", message);
        return jayess_value_undefined();
    }
    stored = (Texture2D *) malloc(sizeof(Texture2D));
    if (stored == NULL) {
        UnloadTexture(texture);
        jayess_throw_error("failed to allocate raylib texture handle");
        return jayess_value_undefined();
    }
    *stored = texture;
    return jayess_value_from_managed_native_handle("RaylibTexture", stored, jayess_raylib_texture_finalize);
}

jayess_value *jayess_raylib_set_trace_log_level(jayess_value *level_value) {
    SetTraceLogLevel((int) jayess_value_to_number(level_value));
    return jayess_value_undefined();
}

jayess_value *jayess_raylib_set_trace_log_callback(jayess_value *callback_value) {
    if (callback_value == NULL || jayess_value_function_ptr(callback_value) == NULL) {
        jayess_throw_not_function();
        return jayess_value_undefined();
    }
    jayess_raylib_trace_log_callback = callback_value;
    return jayess_value_from_bool(1);
}

jayess_value *jayess_raylib_clear_trace_log_callback(void) {
    jayess_raylib_trace_log_callback = NULL;
    return jayess_value_from_bool(1);
}

jayess_value *jayess_raylib_emit_trace_log(jayess_value *level_value, jayess_value *message_value) {
    jayess_value *message = NULL;
    if (jayess_raylib_trace_log_callback == NULL) {
        return jayess_value_from_bool(0);
    }
    message = jayess_value_from_string(jayess_expect_string(message_value, "jayess_raylib_emit_trace_log"));
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    jayess_call_function2(jayess_raylib_trace_log_callback, jayess_value_from_number(jayess_value_to_number(level_value)), message);
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    return jayess_value_from_bool(1);
}

jayess_value *jayess_raylib_set_config_flags(jayess_value *flags_value) {
    SetConfigFlags((unsigned int) jayess_value_to_number(flags_value));
    return jayess_value_undefined();
}

jayess_value *jayess_raylib_init_window(jayess_value *width_value, jayess_value *height_value, jayess_value *title_value) {
    int width = (int) jayess_value_to_number(width_value);
    int height = (int) jayess_value_to_number(height_value);
    const char *title = jayess_expect_string(title_value, "jayess_raylib_init_window");
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    InitWindow(width, height, title);
    if (IsWindowReady()) {
        jayess_raylib_window_width = width;
        jayess_raylib_window_height = height;
        jayess_raylib_windowed_width = width;
        jayess_raylib_windowed_height = height;
        jayess_raylib_window_fullscreen = 0;
    }
    return jayess_value_from_bool(IsWindowReady());
}

jayess_value *jayess_raylib_close_window(void) {
    CloseWindow();
    jayess_raylib_window_width = 0;
    jayess_raylib_window_height = 0;
    jayess_raylib_windowed_width = 0;
    jayess_raylib_windowed_height = 0;
    jayess_raylib_window_fullscreen = 0;
    return jayess_value_undefined();
}

jayess_value *jayess_raylib_is_window_ready(void) {
    return jayess_value_from_bool(IsWindowReady());
}

jayess_value *jayess_raylib_window_should_close(void) {
    return jayess_value_from_bool(WindowShouldClose());
}

